import React, { useState } from 'react';
import { Card, Button, Form, Alert, ListGroup } from 'react-bootstrap';
import axios from 'axios';

function Checkout({ cartItems, onClearCart }) {
  const [phone, setPhone] = useState('');
  const [customers, setCustomers] = useState([]);
  const [selectedCustomer, setSelectedCustomer] = useState(null);
  const [newCustomer, setNewCustomer] = useState({ fullName: '', phone: '', carModel: '' });
  const [showNewCustomer, setShowNewCustomer] = useState(false);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');

  const API_URL = 'http://localhost:5051/api';
  const token = localStorage.getItem('token');
  const user = JSON.parse(localStorage.getItem('user') || '{}');

  const searchCustomers = async () => {
    if (!phone.trim()) return;
    setLoading(true);
    setError('');
    try {
      const response = await axios.get(`${API_URL}/Customers/search?term=${encodeURIComponent(phone)}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setCustomers(response.data);
      if (response.data.length === 0) {
        setError('Клиенты не найдены');
      }
    } catch (err) {
      console.error('Ошибка поиска клиентов:', err);
      setError('Ошибка поиска клиентов');
    }
    setLoading(false);
  };

  const createCustomer = async () => {
    if (!newCustomer.fullName || !newCustomer.phone) {
      setError('Имя и телефон обязательны');
      return;
    }
    setLoading(true);
    setError('');
    try {
      const response = await axios.post(`${API_URL}/Customers`, newCustomer, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setSelectedCustomer(response.data);
      setShowNewCustomer(false);
      setMessage('Клиент создан');
    } catch (err) {
      console.error('Ошибка создания клиента:', err);
      setError('Ошибка создания клиента');
    }
    setLoading(false);
  };

  const createOrder = async () => {
    if (!selectedCustomer) {
      setError('Выберите клиента');
      return;
    }
    if (cartItems.length === 0) {
      setError('Корзина пуста');
      return;
    }

    setLoading(true);
    setError('');
    try {
      const orderData = {
        customerId: selectedCustomer.id,
        userId: user.id,
        items: cartItems.map(item => ({
          partId: item.id,
          quantity: item.quantity
        })),
        notes: ''
      };

      const response = await axios.post(`${API_URL}/Orders`, orderData, {
        headers: { Authorization: `Bearer ${token}` }
      });

      setMessage(`Заказ ${response.data.order.orderNumber} создан! Сумма: ${response.data.order.totalAmount} ₽`);
      onClearCart();
      setSelectedCustomer(null);
    } catch (err) {
      console.error('Ошибка создания заказа:', err);
      setError(err.response?.data?.message || 'Ошибка создания заказа');
    }
    setLoading(false);
  };

  const total = cartItems.reduce((sum, item) => sum + item.retailPrice * item.quantity, 0);

  return (
    <div>
      <h2>🛒 Оформление заказа</h2>

      {message && <Alert variant="success">{message}</Alert>}
      {error && <Alert variant="danger">{error}</Alert>}

      <Card className="mb-3">
        <Card.Header><strong>Товары в заказе</strong></Card.Header>
        <ListGroup variant="flush">
          {cartItems.map((item, i) => (
            <ListGroup.Item key={i}>
              {item.name} | {item.brand} | {item.quantity} шт. x {item.retailPrice} ₽ = {(item.quantity * item.retailPrice).toFixed(2)} ₽
            </ListGroup.Item>
          ))}
        </ListGroup>
        <Card.Body>
          <h5>Итого: {total.toFixed(2)} ₽</h5>
        </Card.Body>
      </Card>

      {!selectedCustomer ? (
        <Card className="mb-3">
          <Card.Header><strong>Поиск клиента по телефону</strong></Card.Header>
          <Card.Body>
            <Form.Group className="mb-3">
              <Form.Control
                placeholder="Введите номер телефона (например +79011234567)"
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && searchCustomers()}
              />
            </Form.Group>
            <Button variant="primary" onClick={searchCustomers} disabled={loading} className="me-2">
              🔍 Найти
            </Button>
            <Button variant="link" onClick={() => setShowNewCustomer(!showNewCustomer)}>
              + Новый клиент
            </Button>

            {customers.length > 0 && (
              <ListGroup className="mt-3">
                {customers.map(c => (
                  <ListGroup.Item key={c.id} action onClick={() => {
                    setSelectedCustomer(c);
                    setError('');
                  }}>
                    <strong>{c.fullName}</strong> | 📞 {c.phone} | 🚗 {c.carModel || 'Авто не указано'}
                  </ListGroup.Item>
                ))}
              </ListGroup>
            )}
          </Card.Body>
        </Card>
      ) : (
        <Card className="mb-3 border-success">
          <Card.Header className="bg-success text-white">
            <strong>✅ Клиент выбран</strong>
            <Button variant="outline-light" size="sm" className="float-end" onClick={() => setSelectedCustomer(null)}>
              Изменить
            </Button>
          </Card.Header>
          <Card.Body>
            <h5>{selectedCustomer.fullName}</h5>
            <p>📞 {selectedCustomer.phone}</p>
            <p>🚗 {selectedCustomer.carModel || 'Не указано'} {selectedCustomer.carYear || ''}</p>
          </Card.Body>
        </Card>
      )}

      {showNewCustomer && (
        <Card className="mb-3">
          <Card.Header><strong>Новый клиент</strong></Card.Header>
          <Card.Body>
            <Form.Control 
              placeholder="Имя *" 
              className="mb-2"
              value={newCustomer.fullName}
              onChange={(e) => setNewCustomer({...newCustomer, fullName: e.target.value})} 
            />
            <Form.Control 
              placeholder="Телефон *" 
              className="mb-2"
              value={newCustomer.phone}
              onChange={(e) => setNewCustomer({...newCustomer, phone: e.target.value})} 
            />
            <Form.Control 
              placeholder="Автомобиль" 
              className="mb-2"
              value={newCustomer.carModel}
              onChange={(e) => setNewCustomer({...newCustomer, carModel: e.target.value})} 
            />
            <Button variant="success" onClick={createCustomer} disabled={loading}>
              ✅ Создать клиента
            </Button>
          </Card.Body>
        </Card>
      )}

      <Button 
        variant="success" 
        size="lg" 
        onClick={createOrder} 
        disabled={loading || !selectedCustomer || cartItems.length === 0} 
        className="w-100"
      >
        {loading ? '⏳ Создание...' : '✅ Оформить заказ'}
      </Button>
    </div>
  );
}

export default Checkout;
